  for(int i = 0; i < N+2; ++i) std::cin >> a[i];



  std::vector<bit2k> xy(N+1, bit2k(min_op,  INF));

  std::vector<bit2k> yx(N+1, bit2k(max_op, -INF));

  for(int y = N; y >= 1; --y) {

    for(int x = N; x > y; --x) { // play for Y

      int res = std::abs(a[N+1] - a[x]);

      res = std::min(res, xy[x].query(N-x));

      yx[y].add(N+1-x, res);

